 62	/*
 63	 * -----------------------------------------------------------------------------
 64	 *        Time stamp generator
 65	 * -----------------------------------------------------------------------------
 66	 */
 67	const char* getTime(void)
 68	{
 69	#define TIME_BUFFER_SIZE  16
 70	  static char time_buffer[TIME_BUFFER_SIZE];
 71	  struct timespec ts;
 72	
 73	  clock_gettime (CLOCK_REALTIME, &ts);
 74	  snprintf(time_buffer, TIME_BUFFER_SIZE, "%.6ld:%.6ld",
 75	           ts.tv_sec % 3600, ts.tv_nsec / 1000);
 76	  return (time_buffer);
 77	}
