 79	/*
 80	 * -----------------------------------------------------------------------------
 81	 *          Return RRC establishment cause
 82	 * -----------------------------------------------------------------------------
 83	 */
 84	const char* rrcCause(char cause)
 85	{
 86	  if (cause == AS_CAUSE_EMERGENCY) {
 87	    return "EMERGENCY";
 88	  } else if (cause == AS_CAUSE_HIGH_PRIO) {
 89	    return "HIGH_PRIORITY";
 90	  } else if (cause == AS_CAUSE_MT_ACCESS) {
 91	    return "MT_ACCESS";
 92	  } else if (cause == AS_CAUSE_MO_SIGNAL) {
 93	    return "MO_SIGNALLING";
 94	  } else if (cause == AS_CAUSE_MO_DATA) {
 95	    return "MO_DATA";
 96	  } else if (cause == AS_CAUSE_V1020) {
 97	    return "V1020";
 98	  } else {
 99	    return "Unknown";
100	  }
101	}
